<div class="page-title-row"><div><p class="text-muted mb-1">Personal alerts</p><h1>Notification Center</h1></div><form method="post" action="/portal/notifications/read-all"><?=csrf_field()?><button class="btn btn-outline-primary"><i class="fa-solid fa-check-double me-2"></i>Mark all read</button></form></div>
<section class="portal-card"><div class="list-group list-group-flush"><?php foreach($notifications as $n):?><div class="list-group-item px-0 py-3 <?=$n['read_at']?'opacity-75':''?>"><div class="d-flex justify-content-between gap-3"><div><div class="d-flex align-items-center gap-2"><span class="badge text-bg-<?=$n['severity']==='critical'?'danger':($n['severity']==='warning'?'warning':'primary')?>"><?=e($n['severity'])?></span><strong><?=e($n['title'])?></strong></div><p class="mb-1 mt-2"><?=e($n['message'])?></p><small class="text-muted"><?=e($n['created_at'])?></small><?php if($n['action_url']):?><div><a href="<?=e($n['action_url'])?>">Open related item</a></div><?php endif?></div><?php if(!$n['read_at']):?><form method="post" action="/portal/notifications/<?=$n['id']?>/read"><?=csrf_field()?><button class="btn btn-sm btn-outline-secondary">Mark read</button></form><?php endif?></div></div><?php endforeach?><?php if(empty($notifications)):?><div class="text-center text-muted py-5">No notifications. A suspiciously peaceful state.</div><?php endif?></div></section>
